Bash(powershell -File - << 'PSEOF'
[xml]$xml = Get-Content 'c:\\Users\\wkkim\\Downloads\\pptx_extracted\\ppt\\slides\\slide2.xml' -Encoding UTF8
$shapes = $xml.sld.cSld.spTree.sp
foreach \($sp in $shapes\) {
    $name = $sp.nvSpPr.cNvPr.name
    $xfrm = $sp.spPr.xfrm
    if \(-not $xfrm\) { $xfrm = $sp.spPr.prstGeom }
    $off = $xfrm.off
    $ext = $xfrm.ext
    $allText = @\(\)
    foreach \($p in $sp.txBody.p\) {
        $line = \($p.r | ForEach-Object { $_.t }\) -join ''
        if \($line\) { $allText += $line }
    }
    $texts = $allText -join ' | '
    $fill = $sp.spPr.solidFill.srgbClr.val
    $x = if \($off\) { [math]::Round\([int]$off.x / 12700, 2\) } else { '' }
    $y = if \($off\) { [math]::Round\([int]$off.y / 12700, 2\) } else { '' }
    $w = if \($ext\) { [math]::Round\([int]$ext.cx / 12700, 2\) } else { '' }
    $h = if \($ext\) { [math]::Round\([int]$ext.cy / 12700, 2\) } else { '' }
    Write-Host "[$name] x=${x}pt y=${y}pt w=${w}pt h=${h}pt fill=#$fill | $texts"
}
PSEOF)
